def maximumLengthSubstring(s: str) -> int:
    n = len(s)
    max_length = 0
    for i in range(n):
        count_dict = {}
        for j in range(i, n):
            char = s[j]
            if char in count_dict:
                count_dict[char] += 1
            else:
                count_dict[char] = 1
            if sum(count_dict.values()) <= 2:
                max_length = max(max_length, j - i + 1)
    return max_length

